"""
MKT Context Commentary — Ephesians chapters 1–4
Run: python3 scripts/zc-context-ephesians-1-4.py

Source data used:
- data/interlinear/ephesians.json
- data/translation/draft/mediating/ephesians.json (MKT text)
- data/commentary/ellicott/ephesians.json (philological background)
- data/parallels/ephesians.json (absorbed into echoes layer separately)

Key decisions in this range:
- "In Ephesus" textual problem (1:1): early papyri P46 and the great uncials omit it; treated as
  a circular letter drafted without a specific addressee, with "in Ephesus" a later scribal addition.
- "Mystery" (1:9; 3:3-6): distinguished sharply from mystery-cult esotericism; Paul's usage is
  rooted in the Jewish raz/mystery tradition of Daniel and 1 Enoch.
- "Dividing wall" (2:14): both the Temple soreg and Torah-as-boundary readings noted; not collapsed.
- Psalm 68:18 citation (4:8): Targum reading ("gave gifts") acknowledged as distinct from MT.
- Vice/virtue lists (4:31-32): identified as a conventional literary form, not enumerated moralizing.
- Humility as counter-cultural virtue (4:2): the Greco-Roman stigma of tapeinophrosynē noted.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EPHESIANS = {
  "1": {
    "1": '<p>Ephesus was the largest city in the Roman province of Asia (modern western Turkey) — a provincial capital, a major Mediterranean port, and home to the Temple of Artemis, one of the seven wonders of the ancient world. Paul\'s three-year residence there (Acts 19:8-10) made it the base for evangelizing the entire province. The phrase "in Ephesus," however, is absent from several of the earliest manuscripts (P46, Codex Vaticanus, Codex Sinaiticus), which simply read "to the holy ones who are also faithful in Christ Jesus." Many scholars conclude Ephesians was a circular letter sent to multiple churches in the region, with the place name left blank to be filled in by the letter-carrier for each destination.</p>',
    "2": '<p>The greeting "grace and peace" (χάρις καὶ εἰρήνη) fuses the standard Greek epistolary greeting (<em>chairein</em>) with the Hebrew shalom (שָׁלוֹם). Paul\'s adaptation is not merely stylistic — by attributing both to "God our Father and the Lord Jesus Christ," he places the two on the same footing as the source of the one unified blessing. The formula appears in every Pauline letter and is now so familiar that its novelty is easily missed: a Jewish blessing and a Greek greeting merged into a new form that signals both communities are addressed.</p>',
    "3": '<p>The opening "Blessed be God" (εὐλογητὸς ὁ θεός) is a Jewish <em>berakah</em> (blessing) formula found throughout the OT and Second Temple literature and in synagogue liturgy. The long sentence that follows (vv. 3–14 in Greek, a single 202-word sentence) is structured like a Jewish prayer of thanksgiving, cataloguing God\'s acts before making any petition. The phrase "heavenly realms" (ἐν τοῖς ἐπουρανίοις) appears five times in Ephesians and nowhere else in Paul — it signals a vertical dimension of reality inhabited by Christ, angelic powers, and now believers. This distinctive spatial frame is central to Ephesians\' theology.</p>',
    "4": '<p>"Holy and blameless" echoes the cultic language of sacrifice — the animals brought to the altar were required to be <em>tamim</em> (without defect, unblemished). Paul transfers this vocabulary from the sacrificial system to the people of God, signalling that what the cult sought through unblemished animals, God purposes in the community through Christ. "Before the foundation of the world" reflects Jewish cosmological thinking, widespread in Second Temple literature, that divine choices precede creation itself (cf. 1 Enoch 39; 4 Ezra 6:6). Election is not a late divine reaction to human events but a pre-creational decision.</p>',
    "5": '<p>Roman adoption (<em>adoptio</em>) was a deliberate legal act that transferred a person fully into a new family, conferring the adopter\'s name, citizenship, and inheritance rights — sometimes used by wealthy men without biological heirs to secure a successor. Unlike birth sons, adopted sons were chosen, making adoption in Roman experience an expression of intentional, deliberate relationship. Paul\'s Gentile readers in Roman Asia Minor would have grasped the force of this immediately: they are not accidental members of the divine family but chosen and formally incorporated into it.</p>',
    "6": '<p>"The One he loves" (τοῦ ἠγαπημένου) is a Semitic idiom for the uniquely beloved — the same phrase stands behind "my beloved Son" at Jesus\'s baptism (Mark 1:11) and transfiguration (Mark 9:7). By placing this at the end of the first strophe ("to the praise of his glorious grace, which he has freely given us in the One he loves"), Paul situates all grace within the Father\'s love for the Son. The grace believers receive is an extension of that prior, eternal love.</p>',
    "7": '<p>Redemption (ἀπολύτρωσις) was a commercial and legal term for the release of a slave or prisoner of war through a ransom payment (<em>lytron</em>). Manumission — the formal purchase and liberation of enslaved persons — was a familiar legal reality across the Roman world; temples sometimes served as intermediaries holding the purchase price. Paul\'s audience would have understood the term concretely, not abstractly. The "forgiveness of trespasses" (παραπτωμάτων) uses the standard Jewish covenant term for acts of faithlessness against God\'s covenant obligations.</p>',
    "8": '<p>The pairing of "wisdom and understanding" (σοφίᾳ καὶ φρονήσει) echoes the Jewish wisdom tradition, where wisdom (חָכְמָה, <em>hokhmah</em>) and understanding (בִּינָה, <em>binah</em>) are characteristic divine attributes extended to those in covenant relationship (Prov 3:19-20; Wis 8:18). The idea of God "lavishing" these on believers uses abundance language characteristic of Ephesians — God gives beyond measure, in the manner of a great patron with inexhaustible resources.</p>',
    "9": '<p>"Mystery" (μυστήριον) in Paul\'s usage must be distinguished from its use in the Greco-Roman mystery cults (Eleusinian, Dionysian, Mithraic), where secret rites were disclosed only through prolonged initiation, and the content was kept hidden from outsiders on pain of divine punishment. Paul\'s <em>mystērion</em> follows the Jewish apocalyptic tradition, where <em>raz</em> (mystery) refers to divine secrets disclosed to prophetic seers (Dan 2:18-19; 1 Enoch 103:2). The crucial difference: Paul\'s mystery is now openly proclaimed — what was hidden is now published to all.</p>',
    "10": '<p>"When the times reach their fulfillment" (πλήρωμα τῶν καιρῶν) is eschatological language for the appointed moment when God\'s plan reaches completion. Jewish eschatology expected "this age" (עוֹלָם הַזֶּה, <em>olam hazeh</em>) to give way to "the age to come" (עוֹלָם הַבָּא, <em>olam haba</em>); Paul presents the Christ-event as the hinge. The verb "to bring unity to all things" (ἀνακεφαλαιώσασθαι) literally means "to sum up under one head" — a rhetorical term for recapitulating an argument\'s main points. Paul uses it for Christ as the cosmic head who draws all scattered reality under his unifying lordship.</p>',
    "11": '<p>"We who were the first to put our hope in Christ" likely refers to Jewish believers who lived within the messianic expectation of the covenant before the Gentiles were included. The sequence — Jews first, then Gentiles (vv. 11-13) — mirrors Paul\'s "to the Jew first and also to the Greek" pattern (Rom 1:16). The "predestined according to the plan of him who works out everything in conformity with the purpose of his will" continues the pre-creational election language of v. 4, now with the forensic note that God\'s plan executes according to his own counsel, not external constraint.</p>',
    "12": '<p>"For the praise of his glory" closes the first strophe of the berakah (v. 6), the second (v. 12), and will close the third (v. 14). This triple refrain structures the prayer as a three-movement blessing, each movement ending in the same doxological phrase. Repetition of a key phrase at structural intervals is a Hebrew rhetorical device; its presence here reinforces the Jewish liturgical character of the passage.</p>',
    "13": '<p>Being "sealed with the promised Holy Spirit" imports the commercial and legal practice of sealing (σφραγίζω). Seals authenticated ownership and guaranteed authenticity — a sealed document could not be opened before the appointed time without destroying evidence of tampering. In Jewish tradition, circumcision was described as the "seal" of the Abrahamic covenant (Rom 4:11). Paul now replaces circumcision with the Spirit as the seal of the new covenant community — a seal accessible to all, male and female, Jew and Gentile. This is among Paul\'s most pointed implicit arguments against requiring circumcision of Gentile believers.</p>',
    "14": '<p>The "deposit guaranteeing our inheritance" (ἀρραβών) is a commercial law term for earnest money — a down payment that legally binds the full transaction to follow. The word is actually a Semitic loanword in Greek, borrowed from Phoenician commercial practice and widely used in Greco-Roman contracts. The concept is precise: the Spirit is not merely a pledge in an informal sense but a legally binding first installment that guarantees the full inheritance will be delivered. The "until the redemption of those who are God\'s possession" uses the same manumission language as v. 7.</p>',
    "15": '<p>Paul\'s thanksgiving and prayer section follows the standard Hellenistic epistolary form: after the opening salutation, the writer gives thanks for the recipients and reports praying for them (cf. Rom 1:8-10; Col 1:3-4; Phil 1:3-5). This was a courtesy convention in ancient letters, but Paul fills it with theological content. "Your faith in the Lord Jesus and your love for all God\'s people" — hearing reports of a community\'s character before visiting them was a standard feature of ancient correspondence, where distance made personal knowledge depend on travelers\' reports.</p>',
    "16": '<p>"Remembering you in my prayers" — Paul participates in the Jewish pattern of fixed prayer times (the <em>tefillah</em>, morning and evening; cf. Acts 3:1; 10:3, 9; Dan 6:10). His intercessory prayer is not spontaneous recollection but structured, regular liturgical memory. The word translated "remembering" (μνείαν ποιούμενος) is a technical phrase for formal memorial — the kind of deliberate recall that shaped Jewish prayer practice.</p>',
    "17": '<p>"The Spirit of wisdom and revelation in the knowledge of him" — in Jewish thought, the Spirit is the agent of prophetic insight and divine wisdom (Isa 11:2; Num 11:25; Wis 7:7). The goal, "the knowledge of him" (ἐπίγνωσις αὐτοῦ), echoes the covenantal knowledge formula of Jeremiah 31:34: "They will all know me." This is not merely intellectual acquaintance but relational recognition — the goal of covenant life.</p>',
    "18": '<p>"The eyes of your heart" — in Hebrew anthropology, the heart (<em>lēb</em> / לֵב) was the seat of understanding, will, and decision, not primarily of emotion as in modern Western usage. Proverbs repeatedly addresses the heart as the center of moral cognition (Prov 4:23; 23:7). The "enlightening" of the heart\'s eyes is a prayer for cognitive and volitional transformation — the capacity to perceive the reality of what God has done. This is a Hebraic framing, not a Platonic or Stoic one.</p>',
    "19": '<p>"His incomparably great power for us who believe" — Paul begins to pile up power-vocabulary in a sequence of four Greek terms (δύναμις, ἐνέργεια, κράτος, ἰσχύς) that together convey overwhelming force. The dense accumulation echoes Jewish doxological language for divine power (Ps 29:1; Isa 40:26). This power language activates the Exodus background — the "mighty hand and outstretched arm" (יָד חֲזָקָה, <em>yad chazaqah</em>) of God in Exodus is the paradigm for divine rescue.</p>',
    "20": '<p>The right hand position was the place of highest honor in ancient Near Eastern and Greco-Roman court protocol — the king\'s most trusted vizier sat at his right hand (cf. Ps 110:1). Paul\'s statement that God "seated him at his right hand in the heavenly realms" presents Christ\'s exaltation in political terms: he is the supreme royal official of the divine court. The "heavenly realms" again signals the cosmic dimension of this enthronement.</p>',
    "21": '<p>"All rule and authority, power and dominion" — these four terms reflect the hierarchy of spiritual beings in Second Temple Jewish cosmology (cf. 1 Enoch 61:10; Col 1:16; Rom 8:38). Jewish apocalyptic literature populated the cosmos with ranked angelic and demonic powers, each governing specific domains. Paul\'s point is not to affirm the cosmology in detail but to use its terms as an exhaustive sweep: Christ is above every member of every tier of the cosmic hierarchy, including powers whose names have not yet been named.</p>',
    "22": '<p>"Head over everything for the church" fuses two conceptual traditions. In Hellenistic political philosophy, the body-politic had a head (the ruler) and members (citizens); the head-body metaphor was used for the relationship between ruler and state (Philo employs it). In Jewish wisdom tradition, Wisdom was present at creation and pervades all things (Wis 7:24). Paul combines these: Christ as head is simultaneously the cosmic ruler and the source of the body\'s life — not merely governor but constitutive source.</p>',
    "23": '<p>"The fullness of him who fills everything in every way" — <em>plēroma</em> (fullness) became a technical term in later Gnostic cosmology, but here it is grounded in the Jewish theology of divine presence. The glory of the Lord "filled" the tabernacle and temple (Exod 40:34-35; 1 Kgs 8:10-11); the eschatological hope was that God\'s presence would fill all the earth (Num 14:21; Hab 2:14). Paul presents Christ\'s fullness as this universal divine presence, now mediated through the church as his body.</p>'
  },
  "2": {
    "1": '<p>"Dead in your transgressions and sins" — the category of spiritual death before God is found in Jewish apocalyptic literature (4 Ezra 7:48) and in the language of covenant curse: the covenant partner who abandons the covenant enters the sphere of curse and death (Deut 28). Paul addresses the Gentile Ephesians as those who had no covenant standing before God, and thus no access to the covenant life. This is not biological death or Greek philosophical dissolution of the soul but the Jewish covenantal category of exclusion from God\'s life-giving presence.</p>',
    "2": '<p>"The ruler of the kingdom of the air" — Second Temple Jewish cosmology located demonic powers in the lower atmosphere between earth and the moon (cf. 1 Enoch 18-19; Testament of Solomon; Jubilees 10). The "air" (ἀήρ) was understood as the domain of spiritual forces hostile to God, which would have resonated with both Jewish and Gentile readers familiar with Greco-Roman demonology. "The spirit who is now at work in those who are disobedient" — a common Jewish designation for the adversarial cosmic power who animates human rebellion against God.</p>',
    "3": '<p>"Children of wrath" is a Hebraic idiom — literally "sons of wrath" (υἱοὶ τῆς ὀργῆς) — meaning those who belong to, or are destined for, wrath. The same construction appears at Qumran: "sons of light" and "sons of darkness" are categories of belonging, not biological descent. "Gratifying the cravings of our flesh" uses the <em>sarx</em> (flesh) language that Paul shares with the Qumran community\'s use of <em>bāśār</em> (flesh) for the sphere of human weakness and moral failure opposed to God\'s Spirit (cf. 1QS III-IV).</p>',
    "4": '<p>"But God, being rich in mercy" — the dramatic reversal introduced by "but God" (ὁ δὲ θεός) is the rhetorical pattern of Jewish lament and prayer: extended description of hopeless human condition followed by divine intervention. This pattern structures the Psalms (e.g., Ps 22) and Jewish confessional prayer (Ezra 9; Neh 9). "Rich in mercy" echoes the Jewish confession of God\'s character: abundant in hesed (covenant-love) and rahamim (merciful compassion) is how God describes himself at Sinai (Exod 34:6) and how Israel prays to him throughout the OT.</p>',
    "5": '<p>"Made us alive together with Christ" (συνεζωοποίησεν) introduces a cluster of compound verbs with the prefix <em>syn-</em> ("together with") that characterizes Ephesians 2:5-6. Believers are co-quickened, co-raised, and co-seated with Christ. This inaugurated eschatology — the claim that believers already share in the resurrection life — is a Christian adaptation of Jewish resurrection hope, which expected resurrection only at the end of the age. The parenthetical "(it is by grace you have been saved)" echoes the refrain of v. 8.</p>',
    "6": '<p>"Seated us with him in the heavenly realms in Christ Jesus" — the realized eschatology here is striking within Jewish categories. Jewish apocalyptic texts described the righteous being exalted to heaven after death or at the end of the age (cf. 1 Enoch 39; 4 Ezra 7); Paul presents this as already accomplished for believers in the present. The spatial claim — that believers\' true location is in the heavenly realms even while they inhabit earthly bodies — is Ephesians\' most distinctive theological move.</p>',
    "7": '<p>"The coming ages" — Jewish eschatology distinguished this age (<em>olam hazeh</em>) from the age to come (<em>olam haba</em>); Paul\'s "ages" (αἰῶνες) in the plural envisions multiple future epochs of divine generosity. The demonstration of God\'s grace toward the Ephesians is not merely for their benefit but a cosmic exhibit — the church as the display space for God\'s inexhaustible riches before the watching creation.</p>',
    "8": '<p>"By grace you have been saved through faith" — the contrast with "works" (v. 9) is not a generic critique of moral effort but a pointed argument about the boundary markers of God\'s covenant community. In Second Temple Judaism, "works" could specifically denote the acts of Torah that distinguished Israel from the nations (circumcision, food laws, Sabbath, purity regulations). Paul\'s claim is that faith — not ethnic or ritual boundary markers — is now the sole criterion of inclusion in the covenant community. "This is not from yourselves, it is the gift of God" — the antecedent of "this" is disputed, but the broader point is clear: the entire salvation, not merely the faith, is God\'s gift.</p>',
    "9": '<p>"Not by works, so that no one can boast" — boasting (καύχησις) in covenantal privilege was a recognized feature of Second Temple Jewish piety: knowing the Torah, circumcision, ancestry from Abraham were grounds for confidence before God (cf. Rom 2:17-20). Paul\'s denial of boasting does not target Gentile self-congratulation but specifically the Jewish claim to covenantal superiority over Gentiles. In the new community, neither group has standing that the other lacks.</p>',
    "10": '<p>"We are God\'s handiwork" (ποίημα) — the term echoes creation vocabulary. Jewish and Hellenistic writers used <em>poiēma</em> for a work of divine or skilled craftsmanship. Paul\'s claim is that believers are God\'s new creation (cf. Isa 65:17; 2 Cor 5:17) — a claim rich with prophetic freight. The works "prepared in advance" echoes predestination language within a covenantal framework: God\'s purposes are not reactive but deliberate, established before the events themselves.</p>',
    "11": '<p>"Gentiles by birth… called \'the Uncircumcision\'" — <em>akrobystia</em> (uncircumcision) was a term of social contempt in the Jewish world. The Maccabean crisis, in which some Jewish men attempted to reverse their circumcision to compete in Hellenistic gymnasia (1 Macc 1:15), had made circumcision a boundary marker with intense emotional weight. The irony in Paul\'s phrase "made in the body by human hands" captures the Jewish polemic against idols (made by human hands) and applies it to circumcision — pointing to its merely external, outward character.</p>',
    "12": '<p>"Excluded from citizenship in Israel" — <em>politeia</em> (citizenship) is Roman political vocabulary for full membership in a civic body with its attendant rights and privileges. Gentiles were political outsiders to Israel\'s covenant community, with no claim on the Abrahamic, Sinaitic, or Davidic covenants ("the covenants of the promise" — Paul uses the plural deliberately). "Without hope and without God in the world" — the Gentile world had eschatological philosophies (Epicurean, Stoic) but no communal hope grounded in a divine promise to a covenant people. The Greek <em>atheos</em> (without God) was actually used as an insult against early Christians who refused to worship the gods — Paul reclaims it to describe the pre-Christian Gentile condition.</p>',
    "13": '<p>"Once far away have been brought near" — the rabbinic distinction between "far" (<em>rahōq</em>) and "near" (<em>qārōv</em>) was a technical category for Gentiles (far from God) and Jews (near, because possessing the covenant). The terminology appears in Isa 57:19, which Paul will cite via v. 17. Paul\'s claim is that Christ has dissolved this foundational soteriological distinction: those who were structurally, categorically far are now brought near — not by becoming Jews, but by the blood of Christ.</p>',
    "14": '<p>"The dividing wall of hostility" — scholars debate two referents: (1) the <em>soreg</em>, the low stone balustrade in the Jerusalem Temple separating the Court of the Gentiles from the inner courts, with inscriptions warning Gentiles that death awaited those who crossed it (two such inscriptions have been found archaeologically, one now in Istanbul); or (2) the Torah itself, functioning as the social and legal barrier between Jew and Gentile. Paul may intend both simultaneously — the Temple\'s literal wall was itself a physical expression of the Torah\'s boundary-marking function.</p>',
    "15": '<p>"Abolishing in his flesh the law with its commands and regulations" — the "ordinances" (<em>dogmata</em>) were the specific legislative provisions of Torah that created and maintained the social barrier between Jews and Gentiles: food laws preventing shared meals, purity regulations governing contact, circumcision marking ethnic membership. Paul does not abolish the moral content of Torah but its function as a community-marking boundary. "To create in himself one new humanity" — a third entity, neither Jew nor Gentile, is Paul\'s striking claim; not Jewish absorption of Gentiles, not Gentile eclipsing of Jews, but a new creation in Christ.</p>',
    "16": '<p>"One body" — <em>sōma</em> (body) was also the standard Greek term for a corporate association, a <em>collegium</em> — one of the many voluntary associations (trade guilds, burial societies, religious groups) that organized civic life in Roman cities. Paul\'s "one body" subverts this familiar social category: the criterion for membership is neither trade, ethnicity, nor devotion to a patron deity, but union with Christ. The reconciliation to God "through the cross" — the cross as instrument of execution was the most shameful death possible in Roman estimation; Paul treats it as the mechanism of peace.</p>',
    "17": '<p>"Peace to you who were far away and peace to those who were near" — Paul cites or paraphrases Isa 57:19, which the rabbis read as addressing Gentiles (far) and Israel (near). The announcement of peace after judgment and exile was the herald\'s proclamation of Isa 52:7 — the messenger running ahead of the returning King to announce that war is over. Paul presents Christ as both the herald and the content of that peace.</p>',
    "18": '<p>"Access to the Father by one Spirit" — <em>prosagōgē</em> (access, audience) was the term for being formally presented into the presence of a monarch or patron — a significant privilege requiring an intermediary. In the Roman imperial court, direct access to the emperor was restricted and required a patron to introduce the petitioner. Paul\'s claim is that through Christ, by the one Spirit, both Jew and Gentile have this royal audience before God — without the ethnic or cultic intermediaries previously required. The tri-personal structure (through Christ, by the Spirit, to the Father) reflects an early Trinitarian pattern of prayer.</p>',
    "19": '<p>"No longer foreigners and strangers" — the terms <em>paroikoi</em> (resident aliens) and <em>xenoi</em> (foreign visitors) defined precise legal categories in Roman civic life: the <em>paroikos</em> lived permanently in a city but lacked full citizenship rights (no vote, restricted property ownership, limited legal protection); the <em>xenos</em> was a temporary visitor with even less standing. Paul declares that Gentile believers are now <em>politeiai</em> (fellow citizens) with full civic standing and <em>oikeioi</em> (household members) — not guests accommodated in the house but family, with the intimacy and inheritance that entails.</p>',
    "20": '<p>"Built on the foundation of the apostles and prophets" — in the context of Ephesians, "prophets" most likely refers to both OT prophets who anticipated the Gentile mission (Isa 49:6; Amos 9:12) and NT prophets active in early churches (cf. Eph 3:5; 4:11). The cornerstone (<em>akrogōniaios</em>) was the critical architectural element placed first, whose precise positioning determined the alignment of the entire structure. Excavations of Hellenistic buildings confirm the cornerstone\'s structural and symbolic importance.</p>',
    "21": '<p>"A holy temple in the Lord" — the temple metaphor for the believing community appears also in 1 Cor 3:16-17 and 2 Cor 6:16. In Jewish theology, the temple was the unique locus of God\'s dwelling (the <em>Shekinah</em>). The loss of the first temple and the perceived inadequacy of the second (which lacked the ark, the Urim and Thummim, and the divine fire) generated a strong expectation of a future restored temple in which God would truly dwell again (Ezek 40-48; 11QT at Qumran). Paul presents the church as the fulfillment of this eschatological expectation — not a building but a community.</p>',
    "22": '<p>The Shekinah (divine presence) had departed from the first temple at its destruction (Ezek 10:18-19; 11:22-23). Second Temple Judaism knew the second temple lacked the ark of the covenant and the visible cloud-glory. The prophetic hope was for God\'s presence to return in the messianic age (Ezek 43:1-5; Hag 2:6-9). Paul declares this hope fulfilled: God\'s Spirit now inhabits the community of believers as his dwelling. The "being built together" (συνοικοδομεῖσθε) is a present passive — ongoing construction, not a finished state.</p>'
  },
  "3": {
    "1": '<p>"The prisoner of Christ Jesus for the sake of you Gentiles" — Paul writes from prison (most likely Rome, c. AD 60-62, though Caesarea and Ephesus are also proposed). In Roman honor-shame culture, imprisonment was a mark of defeat and disgrace; a prisoner\'s clients would be expected to feel shame by association. Paul inverts this: his imprisonment is "for the sake of" the Gentiles, reframing it through the patron-client framework as honorable suffering on behalf of those he serves. The formula "prisoner of Christ Jesus" (not "prisoner of Rome") asserts that his real captor is Christ — Rome holds his body, Christ holds his allegiance and purpose.</p>',
    "2": '<p>"The administration of God\'s grace" — <em>oikonomia</em> (stewardship, household management) is a technical term from Greek household and estate administration. The <em>oikonomos</em> (steward) managed a great household\'s resources on behalf of the master, with delegated authority and significant responsibility. Paul presents himself as the steward of a divine household secret: he did not invent the mystery of Gentile inclusion but received it as a trust from the divine householder and must administer it faithfully. The term also carries the sense of an ordered plan or dispensation.</p>',
    "3": '<p>The contrast with mystery-religion esotericism is implicit but important. In the mystery cults (Eleusinian, Dionysian, Mithraic), initiates underwent preparatory stages before receiving secret knowledge, and they were forbidden on pain of divine punishment from revealing the content to outsiders. Paul\'s <em>mystērion</em> follows the Jewish apocalyptic tradition (Dan 2:18-19; 1 Enoch 103:2; 1QpHab) where <em>raz</em> (mystery) is a divine secret disclosed to selected seers — but disclosed precisely so it can be proclaimed. Paul\'s mystery is the opposite of esoteric: it is now openly announced to all.</p>',
    "4": '<p>"When you read" acknowledges that this letter is being read aloud in the gathered assembly — the standard mode of reception for both epistolary and scriptural texts in antiquity. Ancient readers were auditors, and texts were composed with this oral reception in mind. The act of reading together is itself a participation in the unveiling of the mystery Paul describes.</p>',
    "5": '<p>"Not made known to people in other generations as it has now been revealed" — this does not claim the OT was entirely silent about Gentile inclusion (the OT prophets anticipated it: Isa 49:6; 56:6-8; Amos 9:11-12). The point is that the specific form of that inclusion — Gentiles as co-heirs without becoming Jews, on equal terms through Christ — was not previously disclosed. The full reading of the OT\'s Gentile horizon was not available until the Christ-event provided the hermeneutical key to unlock it.</p>',
    "6": '<p>The three compound "together-with" words Paul coins here have no precedent in Greek or Jewish literature: <em>synklēronoma</em> (co-heirs), <em>syssōma</em> (members-together-of-one-body), <em>symmetocha</em> (co-participants in the promise). The novelty of the coinage signals the novelty of the reality. Jewish proselytes were historically incorporated into Israel by adopting its practices and identity; Paul\'s mystery is co-heirship without assimilation — Gentiles as Gentiles, alongside Jews, in one body.</p>',
    "7": '<p>"The gift of God\'s grace given me through the working of his power" — the double genitive ("gift of grace") followed by "working of power" uses two of the key-term pairs that characterize Ephesians\' power-language (cf. 1:19). Paul grounds his ministry authorization entirely in divine action, not human qualification. This is consistent with his defensive posture in Galatians and 1-2 Corinthians, where his apostolic credentials were challenged.</p>',
    "8": '<p>"Less than the least of all the Lord\'s people" — the Greek superlative of the comparative (<em>elachistoteros</em>) is grammatically an intensified self-deprecation. This is a recognized rhetorical topos in Greco-Roman letter-writing: establishing ethos through exaggerated humility before making a significant claim. Paul employs it also in 1 Cor 15:9 ("least of the apostles") and 1 Tim 1:15 ("worst of sinners"). The convention does not undercut sincerity — it was the form in which genuine humility was expressed in elevated ancient prose.</p>',
    "9": '<p>"Hidden in God since the ages began" — the phrase echoes Jewish language about divine secrets concealed before creation and disclosed in the end-time (Dan 2:22; 1 Enoch 51:3; Wis 6:22). The hiddenness was not arbitrary but purposeful: the fullness of the divine plan could only be disclosed at the point of its execution. The "administration" of this mystery is again the <em>oikonomia</em> term — Paul manages what God has now opened up for public view.</p>',
    "10": '<p>"The rulers and authorities in the heavenly realms" — the angelic and demonic hierarchies of Second Temple cosmology (Ephesians 1:21; Col 1:16; 1 Enoch 61) are the unwitting audience for the church\'s existence. Paul\'s point is that the Jew-Gentile unity of the church is not merely a sociological fact but a cosmic proclamation: the "manifold wisdom" (πολυποίκιλος σοφία) of God — many-colored, variegated — is displayed through the church\'s unprecedented ethnic reconciliation to the watching cosmic hierarchy.</p>',
    "11": '<p>"His eternal purpose accomplished in Christ Jesus our Lord" — the Greek <em>prothesis tōn aiōnōn</em> (purpose of the ages) uses the same pre-temporal framing as Eph 1:4 and 1:9. God\'s plan is not improvised in response to human history but executed from a design established before time. This is not fatalism — the plan required historical participants and human response — but it is a claim that the Gentile mission was no accident or afterthought.</p>',
    "12": '<p>"Boldness and confident access through faith in him" — <em>parrēsia</em> (boldness) was the right of free citizens to speak openly in the assembly — a political right of the <em>politeuma</em> (civic community). It was denied to slaves and foreigners. <em>Prosagōgē</em> (access) was the formal presentation before a monarch or high official — requiring an intermediary patron. Paul presents believers as having both: the free citizen\'s right of bold speech and the courtier\'s granted audience before the divine king — through Christ as the patron who effects the introduction.</p>',
    "13": '<p>"My sufferings for you, which are your glory" — in the Roman patron-client system, a patron\'s honor normally extended to his clients; equally, a patron\'s disgrace shamed them. Paul inverts this: his imprisonment (which in Roman eyes dishonors him) actually produces glory for the Gentile communities he serves. This is the logic of the cross applied to apostolic ministry: what the world reads as shame is, within God\'s economy, the mechanism of honor for others.</p>',
    "14": '<p>Kneeling was not the standard Jewish posture for prayer. Standing, with hands raised, was the norm (cf. 1 Kgs 8:22; Mark 11:25; Neh 8:6). Kneeling was a posture of deep urgency, penitence, or prostration before a superior (cf. Elijah in 1 Kgs 18:42). Paul\'s deliberate note that he kneels (γονύ κάμπτω) signals that this is not routine prayer but an act of particular intensity and submission — his own posture enacting the spirit of the petition he is about to offer.</p>',
    "15": '<p>"From whom every family in heaven and on earth derives its name" — in the ancient world, naming was a covenantal and political act. The one who names exercises authority over what is named (Gen 2:19-20; 17:5). Paul\'s claim is that all ordered communities — whether human or angelic — derive their relational structure from the divine Father. The Greek <em>patria</em> (family, clan, lineage) shares its root with <em>patēr</em> (Father) — Paul may be exploiting this etymology: every <em>patria</em> is named from the <em>Patēr</em>.</p>',
    "16": '<p>"Out of his glorious riches" — the repeated "riches" language across Ephesians (1:7, 18; 2:4, 7; 3:8, 16) reflects the imagery of a great patron with vast, inexhaustible benefactions to distribute. In the Greco-Roman patronage system, the patron\'s generosity was measured by the abundance and continuity of his gifts; those who gave beyond what was expected were celebrated as especially beneficent. Paul applies this framework to God as the ultimate patron whose resources are immeasurable.</p>',
    "17": '<p>"Rooted and established in love" — Paul deploys two standard ancient metaphors for stability: agricultural (rooted, like a tree whose root system determines its resilience) and architectural (established/founded, like a building on a solid foundation). Both images appear in Hellenistic wisdom literature and Greco-Roman philosophical writing about the virtuous person who cannot be moved by circumstances. Paul\'s ground for this stability is love — not philosophical training or moral virtue.</p>',
    "18": '<p>"Wide and long and high and deep" — the four spatial dimensions echo rabbinic and Hellenistic descriptions of the scope of wisdom (Job 11:7-9; Wis 7:24; Sir 24:3-7) and the measurements of the heavenly temple in apocalyptic literature (Ezek 40-48; Rev 21:16). Paul does not explain what the four dimensions measure — the point is vastness beyond measurement. The language deliberately exceeds the categories available to express it.</p>',
    "19": '<p>"That you may be filled to the measure of all the fullness of God" — the language of divine fullness filling the believer picks up temple imagery: the glory of the Lord filled the tabernacle (Exod 40:34) and the temple (1 Kgs 8:10-11; Ezek 43:5). The eschatological hope was that God\'s glory would fill all the earth (Hab 2:14; Num 14:21). Paul applies this filling not to a building but to persons — the believer-as-temple theme of Eph 2:22 reaches its climactic expression here.</p>',
    "20": '<p>The doxology follows a Jewish prayer pattern: acknowledgment of God\'s incomprehensible greatness, exceeding all human petition or imagination, before the closing ascription of glory. Similar structures appear in Jewish liturgical texts (1QH; Neh 9:5) and throughout the Psalms. "According to his power that is at work within us" — the same <em>dunamis</em>/<em>energeia</em> word pair from 1:19-20, now turned inward: the resurrection power that raised Christ is the same power active inside the praying community.</p>',
    "21": '<p>"Throughout all generations, for ever and ever" — the Greek phrase <em>εἰς πάσας τὰς γενεὰς τοῦ αἰῶνος τῶν αἰώνων</em> (into all the generations of the age of ages) is an intensified version of the Jewish doxological formula <em>l\'olam va\'ed</em> (to the age and its age). The multiplication of temporal expressions in the doxology is itself an enactment of the unlimited scope it asserts — human language at its most expansive still falls short of the eternal reality it attempts to describe.</p>'
  },
  "4": {
    "1": '<p>"A life worthy of the calling" (ἀξίως τῆς κλήσεως) — the concept of living in conformity with one\'s status was a central concern of Hellenistic moral philosophy. Stoics spoke of living "according to nature" or "according to reason"; Aristotle\'s ethics centered on virtuous activity consistent with human excellence. Paul takes this form and fills it with a specifically covenantal content: the "calling" is divine election and the vocation it entails, not a philosophical ideal. The ethical imperative (chapters 4-6) rests on the indicative (chapters 1-3) — behavior follows from identity.</p>',
    "2": '<p>Humility (ταπεινοφροσύνη) was not a virtue in Greco-Roman culture — it was a vice, signifying low social status, servility, and the absence of the proper self-regard that a person of quality should maintain. Cicero, Plutarch, and Aristotle all treat excessive self-deprecation as a defect. Paul\'s elevation of humility as a virtue to be actively cultivated is one of the most counter-cultural moves in the NT ethical tradition — it derives from Jewish wisdom (Prov 3:34; Isa 57:15) and is embodied in Christ\'s self-emptying (Phil 2:3-8).</p>',
    "3": '<p>"The bond of peace" (σύνδεσμος τῆς εἰρήνης) — the <em>syndemos</em> (bond, ligament) appears in Stoic cosmological thought as the rational principle that holds the universe together. Paul takes this philosophical cosmological language and applies it to the church community: peace functions as the structural bond of the new social order. The "unity of the Spirit" is not an achievement to be manufactured but a gift to be guarded — "keep" (τηρεῖν) implies preservation, not creation.</p>',
    "4": '<p>The seven unities of vv. 4-6 may reflect an early baptismal creed or catechetical formula used in the instruction of converts before baptism. Early Christian baptism was a public confession event at which the candidate declared their faith; the "one Lord, one faith, one baptism" structure mirrors the credal summaries that developed around baptismal practice (cf. 1 Cor 12:13; Gal 3:27-28). "One hope when you were called" — the Greek "one hope of your calling" ties eschatological expectation to the moment of conversion.</p>',
    "5": '<p>"One Lord, one faith, one baptism" — the terse, staccato rhythm of these three phrases has a creedal quality. "One baptism" distinguished Christian practice from the many ritual washings of the Jewish world (cf. Heb 6:2, "instruction about baptisms" in the plural) and from John\'s baptism. The singularity of Christian baptism — unrepeatable, marking the irreversible transition of belonging — set it apart. The Didache (an early Christian document, c. AD 80-120) preserves debates about whether immersion or pouring was the proper mode, indicating that this one baptism was taken very seriously as a defining act.</p>',
    "6": '<p>"One God and Father of all, who is over all and through all and in all" — the threefold prepositional phrase (<em>hyper, dia, en</em> — over, through, in) echoes Stoic descriptions of the divine Logos permeating all things (cf. Marcus Aurelius; Seneca). Paul takes the Stoic cosmological idiom and applies it to the personal God of Israel. The Jewish confession of the divine unity (Deut 6:4, the <em>Shema</em>: "Hear, O Israel: the LORD our God, the LORD is one") underlies the "one God" claim, but now expanded to include the Father\'s relation to all people in Christ.</p>',
    "7": '<p>The transition from the seven unities to individual diversity in grace (v. 7) mirrors the Jewish wisdom teaching that God gives different gifts to different persons (Wis 7:7-8:1). Paul\'s "according to the measure of Christ\'s gift" presents Christ as the distributing patron who portions out grace-gifts to each member of the community proportionally — not equally, but appropriately.</p>',
    "8": '<p>The citation of Ps 68:18 introduces a significant tradition-history question. The MT reads "you received gifts from men" (the ascending king receives tribute from the defeated); Paul reads "he gave gifts to men" (the ascending king distributes benefactions). The Syriac Peshitta and Aramaic Targum of Ps 68:18 use a reading closer to Paul\'s, and the Targum was the standard Aramaic paraphrase used in synagogue worship — a form of the text Paul\'s Jewish audiences may have known. Whether Paul cites the Targum tradition, interprets the Hebrew with rabbinic flexibility, or follows a pre-existing Christian tradition is debated; what is clear is that the change is deliberate and interpretive.</p>',
    "9": '<p>The parenthetical explanation of "he ascended" implying a prior descent draws on Jewish cosmological thinking about the relationship between heaven and earth. The debate over what the descent refers to — incarnation (Irenaeus), descent into Hades (some ancient interpreters), or simply descent from heaven to earth at the incarnation — was active in the early church. Jewish apocalyptic literature described prophets ascending to heaven (1 Enoch 14; 2 Enoch 3-7) and returning; Paul\'s pattern of descent-then-ascent follows this pattern with Christ as the one who moves between realms definitively.</p>',
    "10": '<p>"In order to fill the whole universe" — <em>tōn ouranōn</em> (the heavens) in the plural echoes Jewish cosmological descriptions of multiple heavens (2 Cor 12:2; 2 Enoch 1-20; T. Levi 2-3), through all of which Christ has ascended to the highest position. The concept of the exalted Lord filling all cosmic space echoes Jewish wisdom traditions where divine Wisdom filled all things (Wis 7:24; Sir 24:3-7); Paul presents Christ as the one who supplants Wisdom as the cosmic ordering principle, now filling all creation from the highest heaven to the lowest earth.</p>',
    "11": '<p>"Apostles, prophets, evangelists, pastors and teachers" — the list reflects the early church\'s functional structure rather than a fixed ecclesiastical hierarchy. Apostles and prophets appear to be itinerant, establishing churches and speaking revelatory words; evangelists similarly mobile; pastors and teachers likely resident in local communities. The single Greek article governing "pastors and teachers" (τοὺς δὲ ποιμένας καὶ διδασκάλους) has led many commentators to understand these as a single linked role — the "pastor-teacher" — rather than two separate offices.</p>',
    "12": '<p>"Works of service" (<em>ergon diakoniās</em>) — <em>diakonia</em> (service) carried connotations of servant work in the Greco-Roman social world; it was associated with low status and was not the language of leadership. Paul\'s elevation of service as the purpose of the gifted leaders — they equip the whole people for <em>diakonia</em> — is counter-cultural. The leaders serve the servants; the goal is the building up of the body, not the display of leadership competence.</p>',
    "13": '<p>"Mature" (<em>teleios</em>) was a term in Hellenistic philosophy (Stoic, Platonic) for the philosophically perfected person who had achieved the complete development of human reason and virtue — the sage, the Stoic wise man. Paul uses the term for corporate rather than individual maturity: the goal is that "we all" reach teleiotēs together, "in the unity of the faith." The Stoic ideal was the solitary wise man; Paul\'s goal is a community that together reaches full stature in Christ.</p>',
    "14": '<p>"Infants, tossed about by the waves" — the image of a ship driven by wind and wave was a standard Hellenistic philosophical metaphor for a person lacking stable wisdom (Plato, <em>Republic</em> 488a-e; Philo, <em>On the Migration of Abraham</em> 148). The technical terms in the next phrase are notable: <em>kubeia</em> (dice-playing) denoted cunning manipulation and sharp practice; <em>methodia tēs planēs</em> (scheming of error/deceit) uses the word for wandering (<em>planē</em>) that gives us "planet" — the wandering stars that were seen as unstable and potentially malevolent. False teaching is described through imagery of cosmic instability.</p>',
    "15": '<p>"Speaking the truth in love" (ἀληθεύοντες ἐν ἀγάπῃ) — in Hellenistic friendship ethics, frank speech (<em>parrēsia</em>) was the virtue of the true friend who told you what you needed to hear, rather than what you wanted to hear — flattery being the mark of the false friend (Plutarch, <em>How to Tell a Flatterer from a Friend</em>). Paul adopts this framework but fills it with love as the governing motive. The goal of truthful speech is not philosophical correction but the growth of the whole body into Christ.</p>',
    "16": '<p>The body metaphor with joints (<em>haphē</em>) and ligaments (<em>syndesmos</em>) engaging each part draws on the ancient medical tradition. Galen and Hippocratic writers described the body\'s unity through the interdependence of its parts — a wound to one member affects the whole. The Stoics used body-as-cosmos imagery to argue for the interconnectedness of all things. Paul applies this medical and philosophical body-language to the church, but gives it a distinctive head: the body grows only "from him" (ἐξ οὗ — from whom, i.e., from Christ).</p>',
    "17": '<p>"The futility of their thinking" (ματαιότης τοῦ νοὸς) — the term <em>mataiotēs</em> (futility, vanity) is the word used throughout Ecclesiastes (LXX) for the emptiness of life under the sun. In Jewish polemical tradition, Gentile idolatry was characterized as thinking that leads nowhere — the mind worships what cannot see or speak or act, and is consequently darkened (cf. Wis 13:1-9; Rom 1:21). Paul\'s "Gentile mind" is a forensic category — what they were before conversion — not a permanent ethnic characteristic.</p>',
    "18": '<p>"Hardened in heart" (<em>pōrōsis tēs kardias</em>) echoes the OT tradition of divine hardening as judgment on persistent rejection: pharaoh\'s heart (Exod 9:12); Israel\'s hardening in Isa 6:10 (cited in all four Gospels and Acts 28). The heart in Hebrew anthropology is the seat of will and moral cognition; a hardened heart is one that has lost the capacity to respond to what it knows. Moral insensitivity and cognitive blindness are two aspects of the same condition — willful rejection leading to incapacity.</p>',
    "19": '<p>"Having lost all sensitivity" (ἀπηλγηκότες) — the verb means to have become calloused, to have ceased to feel pain. The medical image is precise: a part of the body that has been repeatedly damaged may lose its pain receptors and can no longer register further injury. The Stoics described the morally degraded person similarly — unable to feel the sting of conscience. Having given themselves over to sensuality, these persons have entered a self-reinforcing cycle: insensitivity enables indulgence, which deepens insensitivity.</p>',
    "20": '<p>"That, however, is not the way of life you learned" — the emphatic "you" (ὑμεῖς δέ) marks the contrast with the Gentile lifestyle just described. The formula "learned Christ" (ἐμάθετε τὸν Χριστόν) is unusual — one learns a teacher\'s doctrine, not the teacher himself. Paul\'s phrasing suggests that Christ is not merely the subject of instruction but the content and the teacher simultaneously.</p>',
    "21": '<p>"Were taught in him in accordance with the truth that is in Jesus" — the vocabulary of learning (μαθεῖν), hearing (ἀκοῦσαι), and being taught (διδαχθῆναι) is the technical language of discipleship and catechesis in the ancient synagogue and early church. The pattern — learn from a teacher, hear the tradition, be formally instructed — was how moral formation worked in both Jewish and Hellenistic education. Paul presents conversion as entry into a comprehensive educational formation, not merely a change of belief.</p>',
    "22": '<p>"Put off your old self" — the clothing metaphor for moral transformation was common in both Jewish and Hellenistic moral literature. In Jewish tradition, the high priest\'s garments symbolized moral status (Zech 3:3-5); Isaiah uses clothing for righteousness and salvation (Isa 61:10). In Hellenistic tradition, Stoic writers described the philosopher "putting on" virtue and "taking off" vice. Early Christian baptism was accompanied by an actual change of garment, making the metaphor liturgically enacted as well as conceptually expressed.</p>',
    "23": '<p>"Be made new in the attitude of your minds" (ἀνανεοῦσθαι τῷ πνεύματι τοῦ νοὸς ὑμῶν) — the renewal of the <em>nous</em> (mind, rational faculty) directly contrasts with the "futility of their thinking" (<em>mataiotēs tou noos</em>) in v. 17. The transformation Paul envisions is cognitive and volitional, not merely behavioral — it is the mental frame that generates the behavior, and it must be continuously renewed (present passive infinitive: ongoing action, not a single event).</p>',
    "24": '<p>"The new self, created to be like God in true righteousness and holiness" — the "new self" language evokes the creation of humanity in God\'s image (Gen 1:26-27). The Fall had marred that image; the new creation in Christ restores it. The pair <em>dikaiosunē</em> (righteousness) and <em>hosiotēs</em> (holiness/piety) is the standard Greek ethical pair for justice toward fellow humans and piety toward God — found in Plato, Thucydides, and in Jewish writings (cf. Luke 1:75). Paul\'s "new self" is not a privatized spiritual state but an embodied social and relational reality.</p>',
    "25": '<p>"We are all members of one body" — the <em>mele</em> (members) language returns to the body metaphor of vv. 12-16. In Roman legal theory, members of the same <em>corpus</em> (corporation, association) had mutual obligations defined by their shared membership. Paul grounds the obligation to truthful speech not in general ethics but in ecclesial identity: lying to fellow church members is like a body part deceiving itself.</p>',
    "26": '<p>"In your anger do not sin" is a citation of Ps 4:4 (LXX). The Psalm was an evening prayer (its heading notes it was "for the director of music"), and the following verse about "while you are on your beds" supports reading this as advice not to let anger carry over through the night. The principle "do not let the sun go down on your anger" may echo Deut 24:15, which forbids withholding a laborer\'s wages overnight — a similar principle of not allowing unfulfilled obligations to accumulate past the day\'s end.</p>',
    "27": '<p>"Do not give the devil a foothold" — <em>topos</em> (place, opportunity) is both a military and a legal term: a <em>topos</em> is a strategic position in battle, or a ground for legal action. The image is tactical: allowing anger to persist overnight gives the adversary an established position from which to launch further operations. The identification of the adversary as "the devil" (ὁ διάβολος) uses the Greek term for the accuser or slanderer — the one who operates through accusation and deception.</p>',
    "28": '<p>Manual labor was despised by the social elite in Greco-Roman society as incompatible with the dignity of a gentleman. Cicero (<em>De Officiis</em> I.150-151) lists tradesmen and manual workers among those whose occupation "cannot be gentlemanly" because it requires selling labor. Jewish tradition had a different evaluation — the rabbis worked trades alongside teaching (Paul himself was a tentmaker). Paul\'s elevation of hand-work as the means of earning and of giving to those in need is counter-cultural relative to Greco-Roman social values.</p>',
    "29": '<p>"Unwholesome talk" — <em>sapros</em> (rotten, decayed) was used for food that had spoiled and for wood that had rotted. Applied to speech, it signals talk that corrupts rather than nourishes. The positive alternative — speech that "ministers grace" to hearers — uses the <em>charis</em> vocabulary that runs through Ephesians: even conversation participates in the economy of grace or its opposite. The "need" of the hearer, not the preference of the speaker, determines what is appropriate.</p>',
    "30": '<p>"Do not grieve the Holy Spirit" — the background is Isa 63:10: "they rebelled and grieved his Holy Spirit." Isaiah\'s account of Israel\'s rebellion in the wilderness becomes Paul\'s warning to the Ephesian community. The verb <em>lypeite</em> (grieve) implies that the Spirit is a personal agent who can be hurt by behavior — one grieves a person, not a force or an influence. "Sealed for the day of redemption" returns to the seal language of 1:13-14: the Spirit\'s presence is the mark of divine ownership, guaranteed until the final redemption.</p>',
    "31": '<p>"Bitterness, rage, anger, brawling, slander, along with every form of malice" — this vice list (<em>pikria, thymos, orgē, kraugē, blasphēmia, kakia</em>) follows a conventional Hellenistic and Jewish pattern of moral instruction. Vice and virtue lists were standard teaching forms in Stoic diatribe, Jewish wisdom literature (Wis 14:25-26; T. Gad 5:1), and early Christian catechesis (Col 3:8; Gal 5:19-21). The listing itself was a mnemonic form, intended to be memorized and reviewed in moral self-examination.</p>',
    "32": '<p>"Forgiving each other, just as in Christ God forgave you" — Hellenistic moral philosophy encouraged forgiveness as a virtue of the magnanimous person: the truly great-souled (μεγαλόψυχος) person does not hold grudges because they consider offenses beneath their dignity. Paul\'s ground is entirely different: forgiveness is grounded in the prior forgiveness received from God, not in personal nobility or the insignificance of the offense. The "just as" (καθώς) is normative and specific — the scope and character of divine forgiveness in Christ sets the pattern for human forgiveness.</p>'
  }
}


def main():
    existing = load_comm('mkt-context', 'ephesians')
    merge_comm(existing, EPHESIANS)
    save_comm('mkt-context', 'ephesians', existing)
    print('Ephesians 1–4 mkt-context written.')

if __name__ == '__main__':
    main()
